div.t-attf-style:
max-width: 90%;
padding: 6px 10px;
border-radius: 10px;
font-size: 13px;
line-height: 1.4;
word-break: break-word;
{{ msg.from === 'user'
    ? 'align-self: flex-end; background: #9EA700; color: white; border-bottom-right-radius: 2px;'
    : msg.type === 'error'
        ? 'align-self: flex-start; background: #fdecea; color: #c62828; border: 1px solid #f5c6c6; border-bottom-left-radius: 2px;'
        : 'align-self: flex-start; background: #f0f0f0; color: #333; border-bottom-left-radius: 2px;'
}}
